end

function LModel:SetCacheValueByKey(refName,refId,key,value)
	if not self._refCache then
		self._refCache = {}
	end

	local refTableList = self._refCache[refName]
	if not refTableList then
		refTableList = {}
		self._refCache = refTableList
	end

