end

function LModel:GetConfigValueImpl(refName,refId,key,parseFun)
	local value = self:GetCacheValueByKey(refName,refId,key)
	if value then
		return value
	end
	local ref = self:GetModelConfig(refName)
	if not ref then
		return
	end

	value = ref[refId]
	if not value then
		return
	end
	value = value[key]
	if not value then
		return
	end
	if parseFun then
		value = parseFun(value)
	end

	self:SetCacheValueByKey(refName,refId,key,value)
	return value
end

function LModel:GetParaConfigValueImpl(refName,key,parseFun)
	local value = self:GetCacheParaValueByKey(refName,key)
	if value then
		return value
	end

	local ref = self:GetModelConfig(refName)
	if not ref then
		return
	end

	value = ref[key]
	if value and parseFun then
		value = parseFun(value)
	end

	self:SetCacheParaValueByKey(refName,key,value)
	return value
end


